import { getCached, setCached, invalidateBySource, invalidateAll, clearCache } from '../../src/mcp/hlmm/hlmm_cache';

describe('hlmm_cache', () => {
  beforeEach(() => clearCache());

  const mockPkg = {
    package_id: 'pkg-1',
    profile_id: 'standard_worker',
    budget_class: 'B2',
    source_nodes: [],
    provenance_links: [],
    freshness_age_seconds: 0,
    missing_context_notes: [],
    confidence: 1.0,
    assembled_at: new Date().toISOString(),
  };

  it('returns null for cache miss', () => {
    expect(getCached('t1', 'p1', 'standard_worker', new Map())).toBeNull();
  });

  it('returns cached package on hit with matching freshness', () => {
    const timestamps = new Map([['node-1', new Date(1000)]]);
    setCached('t1', 'p1', 'standard_worker', mockPkg, timestamps);
    const result = getCached('t1', 'p1', 'standard_worker', new Map([['node-1', new Date(1000)]]));
    expect(result).not.toBeNull();
    expect(result?.package_id).toBe('pkg-1');
  });

  it('treats stale entry as cache miss', () => {
    const oldTimestamp = new Map([['node-1', new Date(1000)]]);
    setCached('t1', 'p1', 'standard_worker', mockPkg, oldTimestamp);
    // Now freshness has updated (newer timestamp)
    const result = getCached('t1', 'p1', 'standard_worker', new Map([['node-1', new Date(2000)]]));
    expect(result).toBeNull();
  });

  it('invalidateBySource removes correct entries', () => {
    const timestamps = new Map([['node-1', new Date(1000)], ['node-2', new Date(1000)]]);
    setCached('t1', 'p1', 'standard_worker', mockPkg, timestamps);
    const count = invalidateBySource('node-1', 't1');
    expect(count).toBe(1);
    expect(getCached('t1', 'p1', 'standard_worker', timestamps)).toBeNull();
  });

  it('invalidateBySource leaves unrelated entries intact', () => {
    const timestamps = new Map([['node-X', new Date(1000)]]);
    setCached('t1', 'p1', 'standard_worker', mockPkg, timestamps);
    const count = invalidateBySource('node-not-in-package', 't1');
    expect(count).toBe(0);
    expect(getCached('t1', 'p1', 'standard_worker', timestamps)).not.toBeNull();
  });

  it('invalidateAll removes all entries for tenant+project', () => {
    const ts = new Map<string, Date>();
    setCached('t1', 'p1', 'standard_worker', mockPkg, ts);
    setCached('t1', 'p1', 'architect', mockPkg, ts);
    const count = invalidateAll('t1', 'p1');
    expect(count).toBe(2);
  });
});

