// ─── Mock MQTT module ─────────────────────────────────────────────────────────

class MockMqttClient extends EventEmitter {
  public subscriptions: string[] = [];
  public publishedMessages: Array<{ topic: string; payload: string }> = [];

  subscribe = jest.fn((topics: string | string[], callback?: Function) => {
    const list = Array.isArray(topics) ? topics : [topics];
    this.subscriptions.push(...list);
    if (callback) callback(null);
  });

  publish = jest.fn((topic: string, payload: string) => {
    this.publishedMessages.push({ topic, payload });
  });

  end = jest.fn();
}

let mqttClient: MockMqttClient;
let mqttMock: { connect: jest.Mock };

jest.mock('mqtt', () => {
  const factory = {
    connect: jest.fn(() => {
      mqttClient = new MockMqttClient();
      return mqttClient;
    }),
  };
  mqttMock = factory;
  return factory;
});

// Restore the mqtt.connect implementation after resetMocks resets it
function restoreMqttConnect() {
  (mqttMock.connect as jest.Mock).mockImplementation(() => {
    mqttClient = new MockMqttClient();
    return mqttClient;
