const JWT_SECRET = process.env.JWT_SECRET ?? 'test_jwt_secret_for_testing_only';

// ─── Helpers ─────────────────────────────────────────────────────────────────

function makeToken(payload: object, secret = JWT_SECRET, options: jwt.SignOptions = { expiresIn: '1h' }) {
  return jwt.sign(payload, secret, options);
}

function buildMockRes() {
  const res: Partial<Response> = {
    status: jest.fn().mockReturnThis(),
    json: jest.fn().mockReturnThis(),
    setHeader: jest.fn().mockReturnThis(),
  };
  return res as Response;
}

function buildMockReq(authHeader?: string): AuthenticatedRequest {
  const req = {
    headers: authHeader ? { authorization: authHeader } : {},
    ip: '127.0.0.1',
    socket: { remoteAddress: '127.0.0.1' },
  } as AuthenticatedRequest;
  return req;
}

