describe('JWT token generation', () => {
  it('GIVEN valid userId and tenantId WHEN signed THEN token decodes to the same claims', () => {
    const payload = { userId: 'user-001', tenantId: 'tenant-alpha' };
    const token = makeToken(payload);
    const decoded = jwt.verify(token, JWT_SECRET) as any;

    expect(decoded.userId).toBe('user-001');
    expect(decoded.tenantId).toBe('tenant-alpha');
  });

  it('GIVEN two different tenants WHEN tokens are generated THEN each token only contains its own tenantId', () => {
    const tokenA = makeToken({ userId: 'user-A', tenantId: 'tenant-A' });
    const tokenB = makeToken({ userId: 'user-B', tenantId: 'tenant-B' });

    const decodedA = jwt.verify(tokenA, JWT_SECRET) as any;
    const decodedB = jwt.verify(tokenB, JWT_SECRET) as any;

    expect(decodedA.tenantId).toBe('tenant-A');
    expect(decodedB.tenantId).toBe('tenant-B');
    expect(decodedA.tenantId).not.toBe(decodedB.tenantId);
  });

  it('GIVEN an expiry of 24h WHEN decoded THEN exp claim is approximately 24 hours from now', () => {
    const token = makeToken({ userId: 'u1', tenantId: 't1' }, JWT_SECRET, { expiresIn: '24h' });
    const decoded = jwt.verify(token, JWT_SECRET) as any;
    const expectedExp = Math.floor(Date.now() / 1000) + 86400;
    expect(decoded.exp).toBeGreaterThanOrEqual(expectedExp - 5);
    expect(decoded.exp).toBeLessThanOrEqual(expectedExp + 5);
  });
});

